function 加载多语言文本()
{
   LangrageLoad = new XML();
   LangrageLoad.load(多语言文档地址);
}
function 多语言文档解析(文档)
{
   var _loc3_ = 文档.split("\r\n");
   多语言json文档 += "{";
   var _loc4_ = 0;
   while(_loc4_ < _loc3_.length)
   {
      var _loc5_ = _loc3_[_loc4_].split("=");
      多语言json文档 += "\"" + _loc5_[0] + "\":\"" + _loc5_[1] + "\"";
      if(_loc4_ < _loc3_.length - 1)
      {
         多语言json文档 += ",";
      }
      _loc4_ += 1;
   }
